   287→            improved_response: '', specific_tips: ['Try again for detailed coaching tips'],
   288→            common_mistake: '', practice_prompt: ''
   289→          },
   290→          communication: { score: 5, word_count: 0, words_per_minute: 0, duration_seconds: duration_seconds || 60,
   291→            filler_words: {}, total_fillers: 0, filler_rate: 0, pace: 'unknown', tips: [],
   292→            voice_analysis: null },
   293→          presentation: { score: 5, eye_contact: { score: 5, feedback: 'Analysis unavailable' },
   294→            facial_expressions: { score: 5, feedback: 'Analysis unavailable' },
   295→            body_language: { score: 5, feedback: 'Analysis unavailable' },
   296→            professional_appearance: { score: 5, feedback: 'Analysis unavailable' },
   297→            summary: 'Video analysis could not be completed.', timestamped_notes: [] }
   298→        }
   299→      });
   300→    }
   301→
   302→    await pool.query(
   303→      `INSERT INTO practice_sessions
   304→       (user_id, question_id, question, category, response_text, score, coaching_data, response_type, transcription, audio_analysis, video_analysis, duration_seconds, created_at)
   305→       VALUES ($1, $2, $3, $4, $5, $6, $7, 'video', $8, $9, $10, $11, NOW())`,
   306→      [
   307→        req.user.id,
   308→        question_id,
   309→        question,
   310→        category,
   311→        transcription,
   312→        Math.round(coaching.overall_score || 5),
   313→        JSON.stringify(coaching),
   314→        transcription,
   315→        JSON.stringify(coaching.communication || {}),
   316→        JSON.stringify(coaching.presentation || {}),
   317→        duration_seconds || 60
   318→      ]
   319→    );
   320→
   321→    res.json({
   322→      success: true,
   323→      coaching
   324→    });
   325→  } catch (err) {
   326→    console.error('[QP] Submit video practice response error:', err.message || err);
   327→    if (err.message === 'Analysis timeout' || err.allProvidersFailed) {
   328→      return res.status(503).json({
   329→        error: 'AI analysis is temporarily slow. Please try again in a moment.',
   330→        retryable: true,
   331→        retryAfterMs: 3000,
   332→      });
   333→    }
   334→    res.status(500).json({ error: 'Failed to analyze video response. Please try again.' });
   335→  }
   336→});
   337→
   338→// ─── GET /practice/stats ────────────────────────────────────────
   339→router.get('/practice/stats', authMiddleware, async (req, res) => {
   340→  try {
   341→    const stats = await pool.query(
   342→      `SELECT
   343→        COUNT(*) as total_questions,
   344→        AVG(score) as average_score,
   345→        MAX(created_at) as last_practice
   346→       FROM practice_sessions
   347→       WHERE user_id = $1`,
   348→      [req.user.id]
   349→    );
   350→
   351→    const improvement = await pool.query(
   352→      `WITH ordered_sessions AS (
   353→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   354→               COUNT(*) OVER () as total
   355→        FROM practice_sessions
   356→        WHERE user_id = $1
   357→      )
   358→      SELECT
   359→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   360→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   361→      FROM ordered_sessions`,
   362→      [req.user.id]
   363→    );
   364→
   365→    let improvementPercent = null;
   366→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   367→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   368→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   369→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   370→    }
   371→
   372→    const streakResult = await pool.query(
   373→      `WITH RECURSIVE date_series AS (
   374→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   375→        UNION ALL
   376→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   377→        FROM date_series
   378→        WHERE days_back < 30
   379→      )
   380→      SELECT COUNT(*) as streak
   381→      FROM date_series d
   382→      WHERE EXISTS (
   383→        SELECT 1 FROM practice_sessions
   384→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   385→      )
   386→      AND d.check_date <= CURRENT_DATE
   387→      AND NOT EXISTS (
   388→        SELECT 1 FROM date_series d2
   389→        WHERE d2.check_date > d.check_date
   390→        AND d2.check_date <= CURRENT_DATE
   391→        AND NOT EXISTS (
   392→          SELECT 1 FROM practice_sessions
   393→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   394→        )
   395→      )`,
   396→      [req.user.id]
   397→    );
   398→
   399→    res.json({
   400→      success: true,
   401→      stats: {
   402→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   403→        average_score: parseFloat(stats.rows[0].average_score) || null,
   404→        improvement: improvementPercent,
   405→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   406→        last_practice: stats.rows[0].last_practice
   407→      }
   408→    });
   409→  } catch (err) {
   410→    console.error('[QP] Get practice stats error:', err);
   411→    res.status(500).json({ error: 'Failed to fetch statistics' });
   412→  }
   413→});
   414→
   415→// ─── GET /practice/progress ─────────────────────────────────────
   416→router.get('/practice/progress', authMiddleware, async (req, res) => {
   417→  try {
   418→    const byCategory = await pool.query(
   419→      `SELECT
   420→        category,
   421→        COUNT(*) as count,
   422→        AVG(score) as average_score
   423→       FROM practice_sessions
   424→       WHERE user_id = $1
   425→       GROUP BY category
   426→       ORDER BY average_score DESC`,
   427→      [req.user.id]
   428→    );
   429→
   430→    const recentSessions = await pool.query(
   431→      `SELECT
   432→        question,
   433→        category,
   434→        score,
   435→        coaching_data->>'improvements' as improvements,
   436→        created_at
   437→       FROM practice_sessions
   438→       WHERE user_id = $1
   439→       ORDER BY created_at DESC
   440→       LIMIT 10`,
   441→      [req.user.id]
   442→    );
   443→
   444→    const sessionsWithParsedData = recentSessions.rows.map(row => {
   445→      let improvements = [];
   446→      try {
   447→        if (row.improvements) {
   448→          improvements = JSON.parse(row.improvements);
   449→        }
   450→      } catch (e) {
   451→        console.error('[QP] Failed to parse improvements:', e);
   452→      }
   453→
   454→      return {
   455→        question: row.question,
   456→        category: row.category,
   457→        score: row.score,
   458→        improvements,
   459→        created_at: row.created_at
   460→      };
   461→    });
   462→
   463→    res.json({
   464→      success: true,
   465→      progress: {
   466→        by_category: byCategory.rows,
   467→        recent_sessions: sessionsWithParsedData
   468→      }
   469→    });
   470→  } catch (err) {
   471→    console.error('[QP] Get practice progress error:', err);
   472→    res.status(500).json({ error: 'Failed to fetch progress' });
   473→  }
   474→});
   475→
   476→// ─── GET /practice/sessions ─────────────────────────────────────
   477→router.get('/practice/sessions', authMiddleware, async (req, res) => {
   478→  try {
   479→    const { limit = 20, offset = 0, category } = req.query;
   480→
   481→    let whereClause = 'WHERE user_id = $1';
   482→    const params = [req.user.id];
   483→
   484→    if (category && category !== 'all') {
   485→      params.push(category);
   486→      whereClause += ` AND category = $${params.length}`;
   487→    }
   488→
   489→    const sessions = await pool.query(
   490→      `SELECT
   491→        id, question_id, question, category, response_text, score,
   492→        coaching_data, response_type, transcription,
   493→        audio_analysis, video_analysis, duration_seconds, created_at
   494→       FROM practice_sessions
   495→       ${whereClause}
   496→       ORDER BY created_at DESC
   497→       LIMIT $${params.length + 1} OFFSET $${params.length + 2}`,
   498→      [...params, Number(limit), Number(offset)]
   499→    );
   500→
   501→    const total = await pool.query(
   502→      `SELECT COUNT(*) as count FROM practice_sessions ${whereClause}`,
   503→      params
   504→    );
   505→
   506→    // BUG FIX #29: For mock interview sessions, compute real category from question_bank
   507→    const mockSessionIds = sessions.rows
   508→      .filter(r => r.question_id && r.question_id.startsWith('mock-'))
