  try {
    const questionLibrary = PRACTICE_QUESTION_LIBRARY;

    const practiceHistory = await pool.query(
      `SELECT question_id, COUNT(*) as times_practiced,
              MAX(score) as best_score,
              AVG(score) as avg_score,
